def bold(func):
    def wrapper(text):
        return '<b>' + func(text) + '</b>'
    return wrapper

def italic(func):
    def wrapper(text):
        return '<i>' + func(text) + '</i>'
    return wrapper

@bold
@italic
def format_text(text):
    return text

print(format_text('hello'))

